def main(arg1: list):
    # 检查输入是否为空
    if not arg1:
        return {"result": []}

    # 将所有字符串合并成一个
    combined_text = "".join(arg1)

    # # 如果合并后为空字符串，返回空数组
    # if not combined_text:
    #     return {"result": []}
    #
    # 按照5000字符进行分片
    chunk_size = 5000
    chunks = []

    for i in range(0, len(combined_text), chunk_size):
        chunks.append(combined_text[i:i + chunk_size])

    return chunks

